class Solution:
  def calculate(self, op: str, num1: float, num2: float) -> float:
    result = 0
    if op == 'add':
      result = num1 + num2
    elif op == 'subtract':
      result = num1 - num2
    elif op == 'multiply':
      result = num1 * num2
    elif op == 'divide':
      if num2 != 0:
        result = num1 / num2
      else:
        result = 'Error: Division by zero'
    return result

